@RunWith(RobolectricTestRunner::class)
class UserCardScreenshotTest {
    @get:Rule val composeTestRule = createComposeRule()
    private val testUser = User("1", "Alice", "alice@example.com")

    @Test
    fun userCard_lightTheme() {
        composeTestRule.setContent {
            MyAppTheme(darkTheme = false) {
                UserCard(user = testUser)
            }
        }
        composeTestRule.onRoot().captureRoboImage(
            "screenshots/UserCard_light.png"
        )
    }

    @Test
    fun userCard_darkTheme() {
        composeTestRule.setContent {
            MyAppTheme(darkTheme = true) {
                UserCard(user = testUser)
            }
        }
        composeTestRule.onRoot().captureRoboImage(
            "screenshots/UserCard_dark.png"
        )
    }
}
